var IoNzIntel = function() {
  "use strict";

  var VERSION = "1.3.1";

  // ---- MODULE DEFINITIONS ----
  // Each module: name, category, description, query(lat,lng) or queryByName(place), parse(data,lat,lng)
  // Modules with queryByName fire on keyword searches even when geocoding fails.
  // Modules with fetchHeaders get custom headers (e.g. Trade Me needs browser-mimicking headers).

  var modules = {
    geocode: {
      name: "Nominatim Reverse Geocode",
      category: "geo",
      description: "Address, suburb, city, postcode from coordinates",
      query: function(lat, lng) {
        return "https://nominatim.openstreetmap.org/reverse?lat=" + lat + "&lon=" + lng + "&format=json&zoom=16&addressdetails=1";
      },
      parse: function(data) {
        if (!data || data.error) return null;
        var a = data.address || {};
        return {
          display: data.display_name,
          road: a.road || a.street || null,
          suburb: a.suburb || a.neighbourhood || a.hamlet || null,
          city: a.city || a.town || a.village || null,
          district: a.county || a.state_district || null,
          region: a.state || null,
          postcode: a.postcode || null,
          country: a.country || null
        };
      }
    },

    search: {
      name: "Nominatim Forward Search",
      category: "geo",
      description: "Coordinates and bounding box from place name",
      queryByName: function(place) {
        return "https://nominatim.openstreetmap.org/search?q=" + encodeURIComponent(place) + "+New+Zealand&format=json&limit=3&addressdetails=1";
      },
      parse: function(data) {
        if (!data || !Array.isArray(data) || data.length === 0) return null;
        return data.map(function(item) {
          return {
            name: item.display_name,
            lat: parseFloat(item.lat),
            lng: parseFloat(item.lon),
            type: item.type,
            boundingBox: item.boundingbox
          };
        });
      }
    },

    quakes: {
      name: "GeoNet Recent Quakes",
      category: "seismic",
      description: "Recent earthquakes near location. Qualifier filters intensity, scope controls radius.",
      qualifierTranslations: {
        "strong": 5,
        "big": 5,
        "major": 5,
        "large": 5,
        "felt": 3,
        "noticeable": 3,
        "moderate": 4,
        "any": 1,
        "all": 1,
        "small": 2,
        "minor": 2
      },
      scopeTranslations: {
        "nearby": 0.5,
        "close": 0.5,
        "local": 1,
        "regional": 2,
        "national": 180,
        "all": 180,
        "country": 180
      },
      query: function(lat, lng, opts) {
        var mmi = 2;
        if (opts && opts.qualifier) {
          var translated = this.qualifierTranslations[opts.qualifier.toLowerCase()];
          if (translated) mmi = translated;
        }
        return "https://api.geonet.org.nz/quake?MMI=" + mmi;
      },
      parse: function(data, lat, lng, opts) {
        if (!data || !data.features) return null;
        var radiusDeg = 1;
        if (opts && opts.scope) {
          var scopeKeys = {
            "nearby": 0.5, "close": 0.5, "local": 1, "regional": 2,
            "national": 180, "all": 180, "country": 180
          };
          var mapped = scopeKeys[opts.scope.toLowerCase()];
          if (mapped) radiusDeg = mapped;
        }
        var limit = 10;
        if (opts && opts.scope) {
          var s = opts.scope.toLowerCase();
          if (s === "national" || s === "all" || s === "country") limit = 50;
          if (s === "top" || s === "biggest") limit = 5;
        }
        var nearby = data.features.filter(function(f) {
          var c = f.geometry.coordinates;
          return Math.abs(c[1] - lat) < radiusDeg && Math.abs(c[0] - lng) < radiusDeg;
        }).slice(0, limit);
        return {
          nearbyCount: nearby.length,
          totalNational: data.features.length,
          radiusDeg: radiusDeg,
          nearest: nearby.map(function(f) {
            return {
              magnitude: f.properties.magnitude,
              depth: f.properties.depth,
              locality: f.properties.locality,
              time: f.properties.time,
              distance_km: Math.round(haversine(lat, lng, f.geometry.coordinates[1], f.geometry.coordinates[0]))
            };
          })
        };
      }
    },

    volcanoes: {
      name: "GeoNet Volcano Alert Levels",
      category: "seismic",
      description: "All NZ volcanic alert levels with distance from location",
      query: function(lat, lng) {
        return "https://api.geonet.org.nz/volcano/val";
      },
      parse: function(data, lat, lng) {
        if (!data || !data.features) return null;
        return data.features.map(function(f) {
          var c = f.geometry.coordinates;
          return {
            name: f.properties.volcanoTitle || f.properties.volcanoID,
            level: f.properties.level,
            activity: f.properties.activity,
            hazards: f.properties.hazards,
            distance_km: Math.round(haversine(lat, lng, c[1], c[0]))
          };
        }).sort(function(a, b) { return a.distance_km - b.distance_km; });
      }
    },

    weather: {
      name: "Open-Meteo Current Weather",
      category: "weather",
      description: "Temperature, wind, conditions from coordinates. Supports current + forecast.",
      timeRangeTranslations: {
        "today": "current",
        "now": "current",
        "right now": "current",
        "this week": "forecast7",
        "next week": "forecast7",
        "weekly": "forecast7",
        "tomorrow": "forecast1",
        "next few days": "forecast3",
        "3 days": "forecast3",
        "3 day": "forecast3"
      },
      query: function(lat, lng, opts) {
        var base = "https://api.open-meteo.com/v1/forecast?latitude=" + lat + "&longitude=" + lng + "&timezone=Pacific%2FAuckland";
        var mode = "current";
        if (opts && opts.time_range) {
          var translated = this.timeRangeTranslations[opts.time_range.toLowerCase()];
          if (translated) mode = translated;
        }
        if (mode === "forecast7") {
          return base + "&current_weather=true&daily=temperature_2m_max,temperature_2m_min,precipitation_sum,weathercode&forecast_days=7";
        }
        if (mode === "forecast3") {
          return base + "&current_weather=true&daily=temperature_2m_max,temperature_2m_min,precipitation_sum,weathercode&forecast_days=3";
        }
        if (mode === "forecast1") {
          return base + "&current_weather=true&daily=temperature_2m_max,temperature_2m_min,precipitation_sum,weathercode&forecast_days=2";
        }
        return base + "&current_weather=true";
      },
      parse: function(data) {
        if (!data) return null;
        var codes = {
          0: "Clear sky", 1: "Mainly clear", 2: "Partly cloudy", 3: "Overcast",
          45: "Fog", 48: "Depositing rime fog",
          51: "Light drizzle", 53: "Moderate drizzle", 55: "Dense drizzle",
          61: "Slight rain", 63: "Moderate rain", 65: "Heavy rain",
          71: "Slight snow", 73: "Moderate snow", 75: "Heavy snow",
          80: "Slight showers", 81: "Moderate showers", 82: "Violent showers",
          95: "Thunderstorm", 96: "Thunderstorm with hail", 99: "Thunderstorm with heavy hail"
        };
        var result = {};
        // Current weather (always present)
        if (data.current_weather) {
          var w = data.current_weather;
          result.current = {
            temperature_c: w.temperature,
            windspeed_kmh: w.windspeed,
            wind_direction: w.winddirection,
            weather_code: w.weathercode,
            conditions: codes[w.weathercode] || "Unknown (" + w.weathercode + ")",
            time: w.time
          };
        }
        // Daily forecast (if requested)
        if (data.daily && data.daily.time) {
          result.forecast = data.daily.time.map(function(day, i) {
            return {
              date: day,
              max_c: data.daily.temperature_2m_max[i],
              min_c: data.daily.temperature_2m_min[i],
              rain_mm: data.daily.precipitation_sum[i],
              conditions: codes[data.daily.weathercode[i]] || "Unknown"
            };
          });
        }
        return result.current || result.forecast ? result : null;
      }
    },

    elevation: {
      name: "Open Elevation",
      category: "geo",
      description: "Metres above sea level from coordinates",
      query: function(lat, lng) {
        return "https://api.open-elevation.com/api/v1/lookup?locations=" + lat + "," + lng;
      },
      parse: function(data) {
        if (!data || !data.results || !data.results[0]) return null;
        return { elevation_m: data.results[0].elevation };
      }
    },

    poi: {
      name: "OpenStreetMap Points of Interest",
      category: "local",
      description: "Schools, shops, parks, hospitals near location. Qualifier filters by type.",
      qualifierTranslations: {
        "restaurants": "amenity=restaurant",
        "restaurant": "amenity=restaurant",
        "food": "amenity=restaurant",
        "eat": "amenity=restaurant",
        "cafes": "amenity=cafe",
        "cafe": "amenity=cafe",
        "coffee": "amenity=cafe",
        "schools": "amenity=school",
        "school": "amenity=school",
        "hospitals": "amenity=hospital",
        "hospital": "amenity=hospital",
        "medical": "amenity=hospital",
        "doctors": "amenity=doctors",
        "doctor": "amenity=doctors",
        "pharmacy": "amenity=pharmacy",
        "pharmacies": "amenity=pharmacy",
        "chemist": "amenity=pharmacy",
        "parks": "leisure=park",
        "park": "leisure=park",
        "supermarkets": "shop=supermarket",
        "supermarket": "shop=supermarket",
        "shops": "shop",
        "shopping": "shop",
        "petrol": "amenity=fuel",
        "fuel": "amenity=fuel",
        "gas station": "amenity=fuel",
        "banks": "amenity=bank",
        "bank": "amenity=bank",
        "atm": "amenity=atm",
        "parking": "amenity=parking",
        "library": "amenity=library",
        "libraries": "amenity=library",
        "churches": "amenity=place_of_worship",
        "church": "amenity=place_of_worship"
      },
      scopeTranslations: {
        "nearby": 1000,
        "close": 500,
        "walking": 1000,
        "driving": 5000,
        "far": 5000
      },
      query: function(lat, lng, opts) {
        var radius = 2000;
        if (opts && opts.scope) {
          var r = this.scopeTranslations[opts.scope.toLowerCase()];
          if (r) radius = r;
        }
        // Build Overpass query — if qualifier or thing matches a POI type, filter to that type
        var filter = null;
        if (opts && opts.qualifier) {
          var translated = this.qualifierTranslations[opts.qualifier.toLowerCase()];
          if (translated) filter = translated;
        }
        // Also check thing field — classify often puts the POI type there
        // e.g. "restaurants near Auckland" → thing:"restaurant"
        if (!filter && opts && opts.thing) {
          var thingTranslated = this.qualifierTranslations[opts.thing.toLowerCase()];
          if (thingTranslated) filter = thingTranslated;
        }
        var overpass;
        if (filter) {
          // Specific type query — more results for the filtered type
          overpass = "[out:json][timeout:10];(node(around:" + radius + "," + lat + "," + lng + ")[" + filter + "];);out 40;";
        } else {
          // General sweep — all amenities and shops
          overpass = "[out:json][timeout:10];(node(around:" + radius + "," + lat + "," + lng + ")[amenity];node(around:" + radius + "," + lat + "," + lng + ")[shop];);out 20;";
        }
        return "https://overpass-api.de/api/interpreter?data=" + encodeURIComponent(overpass);
      },
      parse: function(data) {
        if (!data || !data.elements) return null;
        var categories = {};
        data.elements.forEach(function(el) {
          var type = el.tags.amenity || el.tags.shop || el.tags.leisure || "other";
          if (!categories[type]) categories[type] = [];
          categories[type].push({ name: el.tags.name || "(unnamed)", lat: el.lat, lng: el.lon });
        });
        return { total: data.elements.length, categories: categories };
      }
    },

    wikipedia: {
      name: "Wikipedia Geosearch",
      category: "knowledge",
      description: "Wikipedia articles about nearby places and features",
      query: function(lat, lng) {
        return "https://en.wikipedia.org/w/api.php?action=query&list=geosearch&gscoord=" + lat + "|" + lng + "&gsradius=5000&gslimit=10&format=json&origin=*";
      },
      parse: function(data) {
        if (!data || !data.query || !data.query.geosearch) return null;
        return data.query.geosearch.map(function(item) {
          return {
            title: item.title,
            distance_m: item.dist,
            url: "https://en.wikipedia.org/wiki/" + encodeURIComponent(item.title.replace(/ /g, "_"))
          };
        });
      }
    },

    wikidata: {
      name: "Wikidata Entity Search",
      category: "knowledge",
      description: "Structured knowledge graph data about the location",
      qualifiesWhen: ["place"],
      queryByName: function(place) {
        return "https://www.wikidata.org/w/api.php?action=wbsearchentities&search=" + encodeURIComponent(place) + "&language=en&format=json&origin=*&limit=5";
      },
      parse: function(data) {
        if (!data || !data.search) return null;
        return data.search.map(function(item) {
          return {
            id: item.id,
            label: item.label,
            description: item.description,
            url: item.concepturi
          };
        });
      }
    },

    intensity: {
      name: "GeoNet Measured Intensity",
      category: "seismic",
      description: "Ground shaking intensity measurements across NZ",
      query: function(lat, lng) {
        return "https://api.geonet.org.nz/intensity?type=measured";
      },
      parse: function(data, lat, lng) {
        if (!data || !data.features) return null;
        var sorted = data.features.map(function(f) {
          var c = f.geometry.coordinates;
          return {
            mmi: f.properties.mmi,
            distance_km: Math.round(haversine(lat, lng, c[1], c[0]))
          };
        }).sort(function(a, b) { return a.distance_km - b.distance_km; });
        return {
          nearestStation: sorted[0] || null,
          stationsWithin50km: sorted.filter(function(s) { return s.distance_km <= 50; }).length,
          totalStations: data.features.length
        };
      }
    },

    // ---- TRADE ME MARKETPLACE ----
    // Server-side only (no CORS). Three headers mimic browser request.
    // Returns listings with prices, bids, reserve status.
    // Born: Session 19, 2026-04-06

    trademe: {
      name: "Trade Me Marketplace",
      category: "marketplace",
      description: "NZ marketplace listings with prices, bids, reserve status",
      primaryField: "thing",
      qualifiesWhen: ["thing"],
      qualifierTranslations: {
        "most bids": "BidsMost",
        "most popular": "BidsMost",
        "cheapest": "PriceAsc",
        "lowest price": "PriceAsc",
        "most expensive": "PriceDesc",
        "highest price": "PriceDesc",
        "closing soon": "ExpiryAsc",
        "ending soon": "ExpiryAsc",
        "newest": "ListingDateDesc",
        "just listed": "ListingDateDesc",
        "most time left": "ExpiryDesc"
      },
      queryByName: function(query, opts) {
        var params = "search_string=" + encodeURIComponent(query);
        // Qualifier → sort_order translation (deterministic lookup)
        if (opts && opts.qualifier) {
          var sortOrder = this.qualifierTranslations[opts.qualifier.toLowerCase()];
          if (sortOrder) {
            params = params + "&sort_order=" + sortOrder;
          }
        }
        // Scope → rows (how many results)
        var rows = 20;
        if (opts && opts.scope) {
          var s = opts.scope.toLowerCase();
          if (s === "count" || s === "all" || s === "total") rows = 100;
          if (s === "top" || s === "best" || s === "first") rows = 5;
        }
        params = params + "&rows=" + rows;
        return "https://api.trademe.co.nz/v1/Search/General.json?" + params;
      },
      fetchHeaders: {
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
        "Accept": "application/json",
        "Referer": "https://www.trademe.co.nz/"
      },
      parse: function(data) {
        if (!data || !data.List) return null;
        return {
          totalCount: data.TotalCount,
          page: data.Page,
          pageSize: data.PageSize,
          listings: data.List.map(function(item) {
            return {
              id: item.ListingId,
              title: item.Title,
              startPrice: item.StartPrice,
              buyNowPrice: item.BuyNowPrice || null,
              maxBidAmount: item.MaxBidAmount || null,
              bidCount: item.BidCount || 0,
              hasReserve: item.HasReserve || false,
              reserveState: item.ReserveState || null,
              isNew: item.IsNew || false,
              category: item.Category,
              region: item.Region,
              suburb: item.Suburb,
              closingDate: item.EndDate,
              url: "https://www.trademe.co.nz/a/listing/" + item.ListingId,
              photoUrl: item.PictureHref || null
            };
          })
        };
      }
    }
  };

  // ---- KEYED SLOTS (dormant — need API keys) ----

  var keyedSlots = {
    nzbn: { name: "NZBN Business Registry", keyParam: "Ocp-Apim-Subscription-Key", url: "https://api.business.govt.nz/gateway/nzbn/v5/entities", status: "dormant" },
    stats_nz: { name: "Stats NZ Demographics", keyParam: "key", url: "https://datafinder.stats.govt.nz/services/query/v1/vector.json", status: "dormant" },
    niwa_tides: { name: "NIWA Tide Predictions", keyParam: "x-apikey", url: "https://api.niwa.co.nz/tides/data", status: "dormant" },
    linz_data: { name: "LINZ Property & Address Data", keyParam: "key", url: "https://data.linz.govt.nz/services/api/v1/", status: "dormant" }
  };

  // ---- HAVERSINE DISTANCE ----

  function haversine(lat1, lng1, lat2, lng2) {
    var dLat = (lat2 - lat1) * Math.PI / 180;
    var dLng = (lng2 - lng1) * Math.PI / 180;
    var a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
            Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
            Math.sin(dLng / 2) * Math.sin(dLng / 2);
    return 12742 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  }

  // ---- FETCH WRAPPER ----
  // Accepts optional custom headers per module (e.g. Trade Me needs browser headers).
  // Default headers used for all other modules.

  function fetchJson(url, timeout, customHeaders) {
    var ms = timeout || 10000;
    var headers = customHeaders || { "Accept": "application/json, text/plain, */*" };
    return new Promise(function(resolve, reject) {
      var timer = setTimeout(function() {
        reject(new Error("Timeout after " + ms + "ms"));
      }, ms);
      fetch(url, {
        headers: headers,
        credentials: "omit",
        referrerPolicy: "no-referrer"
      }).then(function(res) {
        clearTimeout(timer);
        if (res.ok) return res.json();
        reject(new Error("HTTP " + res.status));
      }).then(resolve).catch(function(err) {
        clearTimeout(timer);
        reject(err);
      });
    });
  }

  // ---- CORE INVESTIGATION (coordinates + keywords) ----

  function investigate(lat, lng, opts) {
    var options = opts || {};
    var moduleNames = options.modules || Object.keys(modules);
    var start = Date.now();

    // Selective module firing (Guess Who) — only fire modules whose required fields exist
    var active = moduleNames.filter(function(name) {
      if (name === "search") return false;
      var mod = modules[name];
      if (!mod) return false;
      // If module declares qualifiesWhen, ALL listed fields must exist in options
      if (mod.qualifiesWhen) {
        for (var q = 0; q < mod.qualifiesWhen.length; q++) {
          if (!options[mod.qualifiesWhen[q]]) return false;
        }
        return true;
      }
      // No qualifiesWhen — use legacy check: needs coords or place
      if (!mod.query && mod.queryByName && !options.place) return false;
      return true;
    });

    console.log("[sweep] Investigating " + lat + ", " + lng + " | Qualified: " + active.length + "/" + moduleNames.length);

    var tasks = active.map(function(name) {
      var mod = modules[name];
      var url;

      // Contract-aware routing: if module declares primaryField, use that field from options
      // e.g. Trade Me has primaryField:"thing" → uses options.thing instead of options.place
      if (mod.queryByName) {
        var queryValue = null;
        if (mod.primaryField && options[mod.primaryField]) {
          queryValue = options[mod.primaryField];
        } else if (options.place) {
          queryValue = options.place;
        }
        if (queryValue) {
          url = mod.queryByName(queryValue, options);
        } else if (mod.query) {
          url = mod.query(lat, lng, options);
        } else {
          return Promise.resolve({ module: name, status: "no_query" });
        }
      } else if (mod.query) {
        url = mod.query(lat, lng, options);
      } else {
        return Promise.resolve({ module: name, status: "no_query" });
      }

      var headers = mod.fetchHeaders || null;
      return fetchJson(url, null, headers).then(function(data) {
        var parsed = mod.parse(data, lat, lng, options);
        return { module: name, name: mod.name, category: mod.category, status: parsed ? "ok" : "empty", data: parsed };
      }).catch(function(err) {
        return { module: name, name: mod.name, category: mod.category, status: "error", error: err.message };
      });
    });

    return Promise.all(tasks).then(function(results) {
      var response = {
        query: { lat: lat, lng: lng, place: options.place || null, thing: options.thing || null, qualifier: options.qualifier || null, scope: options.scope || null },
        timestamp: new Date().toISOString(),
        version: VERSION,
        duration_ms: Date.now() - start,
        modules: {}
      };
      var ok = 0, errors = 0;
      results.forEach(function(r) {
        response.modules[r.module] = r;
        if (r.status === "ok") ok++;
        if (r.status === "error") errors++;
      });
      response.summary = { total: results.length, ok: ok, errors: errors, empty: results.length - ok - errors };
      console.log("[sweep] Complete | " + ok + "/" + results.length + " modules returned data | " + response.duration_ms + "ms");
      return response;
    });
  }

  // ---- KEYWORD-ONLY INVESTIGATION ----
  // Fires when geocoding fails. Still runs Trade Me, Wikidata, etc.
  // No coordinates — only modules with queryByName fire.

  function investigateKeywordOnly(name, opts) {
    var options = opts || {};
    // Don't set options.place = name here — it contaminates Guess Who filtering.
    // If called from investigatePlace, options.place is already set (real place).
    // If called directly for thing-only queries, options.place should stay null.
    var start = Date.now();

    var keywordModules = Object.keys(modules).filter(function(key) {
      if (key === "search") return false;
      var mod = modules[key];
      if (!mod.queryByName) return false;
      // Selective firing: check qualifiesWhen
      if (mod.qualifiesWhen) {
        for (var q = 0; q < mod.qualifiesWhen.length; q++) {
          if (!options[mod.qualifiesWhen[q]]) return false;
        }
      }
      return true;
    });

    console.log("[sweep] Keyword-only for '" + name + "' | Qualified: " + keywordModules.length);

    var tasks = keywordModules.map(function(key) {
      var mod = modules[key];
      // Contract-aware: use primaryField if declared, otherwise use place name
      var queryValue = name;
      if (mod.primaryField && options[mod.primaryField]) {
        queryValue = options[mod.primaryField];
      }
      var url = mod.queryByName(queryValue, options);
      var headers = mod.fetchHeaders || null;
      return fetchJson(url, null, headers).then(function(data) {
        var parsed = mod.parse(data);
        return { module: key, name: mod.name, category: mod.category, status: parsed ? "ok" : "empty", data: parsed };
      }).catch(function(err) {
        return { module: key, name: mod.name, category: mod.category, status: "error", error: err.message };
      });
    });

    return Promise.all(tasks).then(function(results) {
      var response = {
        query: { place: options.place || null, lat: null, lng: null, thing: options.thing || null, qualifier: options.qualifier || null, scope: options.scope || null },
        timestamp: new Date().toISOString(),
        version: VERSION,
        duration_ms: Date.now() - start,
        geocode: "failed",
        modules: {}
      };
      var ok = 0, errors = 0;
      results.forEach(function(r) {
        response.modules[r.module] = r;
        if (r.status === "ok") ok++;
        if (r.status === "error") errors++;
      });
      response.summary = { total: results.length, ok: ok, errors: errors, empty: results.length - ok - errors };
      console.log("[sweep] Keyword sweep complete | " + ok + "/" + results.length + " modules returned data | " + response.duration_ms + "ms");
      return response;
    });
  }

  // ---- PLACE-BASED INVESTIGATION ----
  // Tries geocoding first. If it works, fires ALL modules (coord + keyword).
  // If geocoding fails, fires keyword-only modules (Trade Me, Wikidata, etc.)
  // "toyota corolla" -> geocode fails -> Trade Me still fires
  // "whanganui" -> geocode works -> everything fires

  function investigatePlace(name, opts) {
    var options = opts || {};
    options.place = name;

    console.log("[sweep] Resolving: " + name);

    return fetchJson(modules.search.queryByName(name)).then(function(data) {
      var parsed = modules.search.parse(data);
      if (!parsed || parsed.length === 0) {
        console.log("[sweep] Geocode failed for '" + name + "' — firing keyword modules only");
        return investigateKeywordOnly(name, options);
      }
      var best = parsed[0];
      console.log("[sweep] Resolved to: " + best.lat + ", " + best.lng);
      return investigate(best.lat, best.lng, options);
    }).catch(function(err) {
      console.log("[sweep] Geocode error: " + err.message + " — firing keyword modules only");
      return investigateKeywordOnly(name, options);
    });
  }

  // ---- PUBLIC API ----

  return {
    version: VERSION,
    investigate: investigate,
    investigatePlace: investigatePlace,
    investigateKeywordOnly: investigateKeywordOnly,
    haversine: haversine,
    status: function() {
      var activeNames = Object.keys(modules);
      var dormantNames = Object.keys(keyedSlots);
      return {
        name: "IoNzIntel",
        version: VERSION,
        born: "Session 16",
        updated: "Session 19",
        description: "Universal Intelligence Kit — location sweep + marketplace + knowledge graph. One kit, all public sources.",
        activeModules: activeNames.length,
        keyedSlots: dormantNames.length,
        modules: activeNames.map(function(key) {
          return { id: key, name: modules[key].name, category: modules[key].category };
        }),
        dormant: dormantNames.map(function(key) {
          return { id: key, name: keyedSlots[key].name, status: "needs_api_key" };
        })
      };
    },
    list: function() {
      var result = {};
      Object.keys(modules).forEach(function(key) {
        result[key] = { name: modules[key].name, category: modules[key].category, description: modules[key].description };
      });
      return result;
    }
  };
}();

if (typeof module !== "undefined" && module.exports) {
  module.exports = IoNzIntel;
}
